import numpy as np

def get_lr_linear(step: int, total_steps: int, lr_max: float,
                  warmup_steps: int) -> float:
    if step <= warmup_steps:
        return float(lr_max * step / max(warmup_steps, 1))
    decay_steps = total_steps - warmup_steps
    remaining = total_steps - step
    return float(lr_max * max(remaining, 0) / max(decay_steps, 1))
